import * as v from 'valibot';

const User = v.object({
  name: v.pipe(
    v.string(), v.minLength(1)
  ),
  age: v.pipe(
    v.number(), v.integer()
  ),
  email: v.pipe(
    v.string(), v.email()
  ),
});

const result = v.safeParse(User, data);

